arguments.new_str:
using Microsoft.EntityFrameworkCore;
class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Blog>(entity =>
        {
            // Breaking change 1: EF 9 renamed "Discriminator" → "$type".
            // Existing documents still use "Discriminator", so pin the old name.
            entity.HasDiscriminator<string>("Discriminator");

            // Breaking change 2: EF 9 changed id format from "EntityName|Key" → "Key".
            // Existing documents use "Blog|<key>", so preserve the old id factory.
            entity.HasPartitionKey(b => b.Id);
            entity.Property(b => b.Id)
                  .ToJsonProperty("id")
                  .HasValueGenerator<LegacyCosmosIdGenerator>();

            // Breaking change 3: EF 9 removed support for HasIndex on Cosmos.
            // Cosmos has no secondary indexes managed by EF; remove HasIndex call.
            // (HasIndex line removed — was: entity.HasIndex(b => b.Name))
        });
    }
}
class Blog { public string Id { get; set; } public string Name { get; set; }

    // Breaking change 4: EF 9 uses sync-over-async by default for Cosmos,
    // but SaveChanges() / ToList() now throw by default.
    // See SyncJob.cs for the fix (switch to async APIs).
}

// Value generator that reproduces the EF 8 "Discriminator|Key" id format.
using Microsoft.EntityFrameworkCore.ChangeTracking;
using Microsoft.EntityFrameworkCore.ValueGeneration;

class LegacyCosmosIdGenerator : ValueGenerator<string>
{
    public override bool GeneratesTemporaryValues => false;
    public override string Next(EntityEntry entry)
        => $"{entry.Metadata.ShortName()}|{Guid.NewGuid()}";
}

