arguments.new_str:
class SyncJob
{
    // Breaking change 4: EF 9 Cosmos provider no longer supports synchronous I/O
    // by default. Switch to async APIs to avoid InvalidOperationException.
    async Task RunAsync(BlogContext context)
    {
        var blogs = await context.Blogs.ToListAsync();
        foreach (var b in blogs) { b.Name = b.Name.Trim(); }
        await context.SaveChangesAsync();
    }
}

